import workerpool, { createParallelFilter } from '@danielsimonjr/workerpool';

// In findDuplicates:
if (entities.length > 1000) {
  // Create parallel filter function
  const pool = workerpool.pool();
  const parallelFilter = createParallelFilter(pool, {
    chunkSize: 100,
    workerFunction: 'filterDuplicates'
  });
  const duplicatePairs = await parallelFilter(
    entityPairs,
    (pair) => calculateSimilarity(pair[0], pair[1]) >= threshold
  );
  await pool.terminate();
  return duplicatePairs;
}

import workerpool from '@danielsimonjr/workerpool';

// Parallel similarity calculation using worker pool
const pool = workerpool.pool(similarityWorkerPath, { maxWorkers: workerpool.cpus - 1 });
const chunks = chunkArray(entities, Math.ceil(entities.length / (workerpool.cpus - 1)));
const results = await Promise.all(
  chunks.map(chunk => pool.exec('calculateSimilarities', [chunk, queryEmbedding]))
);
const similarities = results.flat();
